-- 7. FUNCTIONS
DROP FUNCTION IF EXISTS public."is_admin_user" CASCADE;
CREATE OR REPLACE FUNCTION public.is_admin_user()
 RETURNS boolean
 LANGUAGE sql
 SECURITY DEFINER
AS $function$
  SELECT EXISTS (
    SELECT 1 FROM profiles WHERE id = auth.uid() AND is_admin = true
  );
$function$
;

DROP FUNCTION IF EXISTS public."trg_set_document_no" CASCADE;
CREATE OR REPLACE FUNCTION public.trg_set_document_no()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Eğer gelen document_no bir UUID formatındaysa (36 karakter ve tireler içeriyorsa)
    -- veya bu bir TOPTAN SATIŞ ise ve biz bunun bir UUID olduğunu tahmin ediyorsak
    IF NEW.transaction_type = 'TOPTAN SATIŞ' AND NEW.document_no IS NOT NULL AND length(NEW.document_no) = 36 THEN
        NEW.order_id := NEW.document_no::UUID;
    END IF;

    -- Şimdi document_no'yu OMG formatına çevir (Eğer zaten OMG değilse)
    IF NEW.document_no IS NULL OR NEW.document_no = '' OR LEFT(NEW.document_no, 3) != 'OMG' THEN
        NEW.document_no := get_next_document_no();
    END IF;
    
    RETURN NEW;
END;
$function$
;

DROP FUNCTION IF EXISTS public."get_next_document_no" CASCADE;
CREATE OR REPLACE FUNCTION public.get_next_document_no()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_seq INTEGER;
BEGIN
    v_seq := nextval('document_no_seq');
    RETURN 'OMG' || LPAD(v_seq::text, 7, '0');
END;
$function$
;

DROP FUNCTION IF EXISTS public."update_updated_at_column" CASCADE;
CREATE OR REPLACE FUNCTION public.update_updated_at_column()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$function$
;

DROP FUNCTION IF EXISTS public."process_tosla_payment" CASCADE;
CREATE OR REPLACE FUNCTION public.process_tosla_payment(p_api_secret text, p_company_id uuid, p_amount numeric, p_transaction_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_new_balance NUMERIC(15,2);
BEGIN
    -- Verify custom secret key
    IF p_api_secret != 'b2b_secret_omi_12345!@#' THEN
        RAISE EXCEPTION 'Invalid Internal API Secret';
    END IF;
    -- Add to Balance (Tahsilat)
    UPDATE public.companies SET current_balance = COALESCE(current_balance, 0) + p_amount
    WHERE id = p_company_id RETURNING current_balance INTO v_new_balance;
    -- Log Transaction (Evrak No = Banka Transaction ID)
    VALUES (p_company_id, 'KREDİ KARTI', p_transaction_id, 'Tosla Online Ödeme', 0, p_amount, v_new_balance);
    RETURN jsonb_build_object('success', true, 'new_balance', v_new_balance);
END;
$function$
;

DROP FUNCTION IF EXISTS public."get_all_logic" CASCADE;
CREATE OR REPLACE FUNCTION public.get_all_logic()
 RETURNS TABLE(type text, name text, definition text)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
            BEGIN
                RETURN QUERY 
                SELECT 'FUNCTION'::text, proname::text, pg_get_functiondef(oid)::text 
                FROM pg_proc WHERE pronamespace = 'public'::regnamespace AND proname NOT IN ('exec_sql', 'get_all_logic');
                
                RETURN QUERY
                SELECT 'TRIGGER'::text, tgname::text, pg_get_triggerdef(oid)::text 
                FROM pg_trigger WHERE tgisinternal = false;
            END; $function$
;

DROP FUNCTION IF EXISTS public."place_b2b_order" CASCADE;
CREATE OR REPLACE FUNCTION public.place_b2b_order(p_company_id uuid, p_shipping_address text, p_note text, p_total_amount numeric, p_items jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_order_id UUID;
    v_new_balance NUMERIC(15,2);
    v_item JSONB;
    v_is_locked BOOLEAN;
    v_current_balance NUMERIC(15,2);
    v_risk_limit NUMERIC(15,2);
    v_user_id UUID := auth.uid();
    v_user_role TEXT := auth.role();
BEGIN
    -- 1. YETKİ KONTROLÜ
    IF v_user_role <> 'service_role' THEN
        IF NOT EXISTS (
            SELECT 1 FROM public.profiles 
            WHERE id = v_user_id AND (is_admin = true OR company_id = p_company_id)
        ) AND NOT EXISTS (
            SELECT 1 FROM public.customer_representatives
            WHERE id = v_user_id AND is_active = true
        ) THEN
            RAISE EXCEPTION 'Unauthorized company order';
        END IF;
    END IF;

    -- 2. BAKİYE VE LİMİT BİLGİLERİNİ ÇEK
    SELECT is_prepayment_locked, COALESCE(current_balance, 0), COALESCE(risk_limit, 0) 
    INTO v_is_locked, v_current_balance, v_risk_limit 
    FROM public.companies WHERE id = p_company_id;
    
    -- 3. KONTROL MEKANİZMASI
    IF v_is_locked IS TRUE THEN
        -- Ön ödemeli (kilitli) hesap: Bakiyesi yetmeli
        IF v_current_balance < p_total_amount THEN
            RAISE EXCEPTION 'Yetersiz Bakiye: Ön ödemeli hesaplarda bakiye sipariş tutarını karşılamalıdır.';
        END IF;
    ELSE
        -- Standart hesap: Risk Limiti Kontrolü
        -- ÖNEMLİ: Eğer v_risk_limit 0 ise, bu kontrol tamamen atlanır (SINIRSIZ BORÇ)
        IF v_risk_limit > 0 THEN
            IF (v_current_balance - p_total_amount) < -v_risk_limit THEN
                RAISE EXCEPTION 'Risk Limiti Aşıldı: Sipariş tutarı tanımlı risk limitinizi aşmaktadır.';
            END IF;
        END IF;
    END IF;

    -- 4. SİPARİŞ OLUŞTURMA
    VALUES (p_company_id, p_shipping_address, p_note, p_total_amount, 'pending', NOW())
    RETURNING id INTO v_order_id;

    -- 5. SİPARİŞ KALEMLERİNİ EKLEME
    FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
    LOOP
        VALUES (
            v_order_id, 
            (v_item->>'product_id')::UUID, 
            (v_item->>'quantity')::INT,
            (v_item->>'unit_price')::NUMERIC(15,2), 
            (v_item->>'total_price')::NUMERIC(15,2)
        );
    END LOOP;

    -- 6. BAKİYE DÜŞME VE HAREKET KAYDI
    UPDATE public.companies SET current_balance = COALESCE(current_balance, 0) - p_total_amount
    WHERE id = p_company_id RETURNING current_balance INTO v_new_balance;

    VALUES (p_company_id, 'TOPTAN SATIŞ', v_order_id::text, 'Sipariş Tutarı', p_total_amount, 0, v_new_balance);

    RETURN jsonb_build_object(
        'success', true, 
        'order_id', v_order_id, 
        'new_balance', v_new_balance
    );
END;
$function$
;

DROP FUNCTION IF EXISTS public."place_b2b_order" CASCADE;
CREATE OR REPLACE FUNCTION public.place_b2b_order(p_company_id uuid, p_shipping_address text, p_note text, p_total_amount numeric, p_items jsonb, p_bypass_prepayment boolean DEFAULT false, p_bypass_risk_limit boolean DEFAULT false)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_order_id UUID;
    v_new_balance NUMERIC(15,2);
    v_item JSONB;
    v_is_locked BOOLEAN;
    v_current_balance NUMERIC(15,2);
    v_risk_limit NUMERIC(15,2);
    v_user_id UUID := auth.uid();
    v_user_role TEXT := auth.role();
    v_is_privileged BOOLEAN := FALSE;
BEGIN
    -- 1. YETKİ KONTROLÜ
    IF v_user_role = 'service_role' THEN
        v_is_privileged := TRUE;
    ELSE
        -- Admin veya Müşteri Temsilcisi mi?
        SELECT EXISTS (
            SELECT 1 FROM public.profiles 
            WHERE id = v_user_id AND is_admin = true
        ) OR EXISTS (
            SELECT 1 FROM public.customer_representatives
            WHERE id = v_user_id AND is_active = true
        ) INTO v_is_privileged;

        -- Eğer yetkisizse sadece kendi firmasına sipariş verebilir
        IF NOT v_is_privileged THEN
            IF NOT EXISTS (
                SELECT 1 FROM public.profiles 
                WHERE id = v_user_id AND company_id = p_company_id
            ) THEN
                RAISE EXCEPTION 'Unauthorized company order';
            END IF;
            -- Yetkisiz kullanıcı bypass parametrelerini kullanamaz
            p_bypass_prepayment := FALSE;
            p_bypass_risk_limit := FALSE;
        END IF;
    END IF;

    -- 2. BAKİYE VE LİMİT BİLGİLERİNİ ÇEK
    SELECT is_prepayment_locked, COALESCE(current_balance, 0), COALESCE(risk_limit, 0) 
    INTO v_is_locked, v_current_balance, v_risk_limit 
    FROM public.companies WHERE id = p_company_id;
    
    -- 3. KONTROL MEKANİZMASI
    IF v_is_locked IS TRUE AND NOT p_bypass_prepayment THEN
        -- Ön ödemeli (kilitli) hesap: Bakiyesi yetmeli (Bypass edilmediyse)
        IF v_current_balance < p_total_amount THEN
            RAISE EXCEPTION 'Yetersiz Bakiye: Ön ödemeli hesaplarda bakiye sipariş tutarını karşılamalıdır.';
        END IF;
    ELSIF NOT p_bypass_risk_limit THEN
        -- Standart hesap: Risk Limiti Kontrolü (Bypass edilmediyse)
        -- ÖNEMLİ: Eğer v_risk_limit 0 ise, bu kontrol tamamen atlanır (SINIRSIZ BORÇ)
        IF v_risk_limit > 0 THEN
            IF (v_current_balance - p_total_amount) < -v_risk_limit THEN
                RAISE EXCEPTION 'Risk Limiti Aşıldı: Sipariş tutarı tanımlı risk limitinizi aşmaktadır.';
            END IF;
        END IF;
    END IF;

    -- 4. SİPARİŞ OLUŞTURMA
    VALUES (p_company_id, p_shipping_address, p_note, p_total_amount, 'pending', NOW())
    RETURNING id INTO v_order_id;

    -- 5. SİPARİŞ KALEMLERİNİ EKLEME
    FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
    LOOP
        VALUES (
            v_order_id, 
            (v_item->>'product_id')::UUID, 
            (v_item->>'quantity')::INT,
            (v_item->>'unit_price')::NUMERIC(15,2), 
            (v_item->>'total_price')::NUMERIC(15,2)
        );
    END LOOP;

    -- 6. BAKİYE DÜŞME VE HAREKET KAYDI
    UPDATE public.companies SET current_balance = COALESCE(current_balance, 0) - p_total_amount
    WHERE id = p_company_id RETURNING current_balance INTO v_new_balance;

    VALUES (p_company_id, 'TOPTAN SATIŞ', v_order_id::text, 'Sipariş Tutarı', p_total_amount, 0, v_new_balance);

    RETURN jsonb_build_object(
        'success', true, 
        'order_id', v_order_id, 
        'new_balance', v_new_balance
    );
END;
$function$
;

DROP FUNCTION IF EXISTS public."handle_new_user" CASCADE;
CREATE OR REPLACE FUNCTION public.handle_new_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
begin
  values (
    new.id, 
    coalesce(new.raw_user_meta_data->>'full_name', 'New User'),
    false
  );
  return new;
exception when others then
  return new;
end;
$function$
;

DROP FUNCTION IF EXISTS public."is_admin" CASCADE;
CREATE OR REPLACE FUNCTION public.is_admin()
 RETURNS boolean
 LANGUAGE sql
 SECURITY DEFINER
AS $function$ SELECT COALESCE(is_admin, false) FROM profiles WHERE id = auth.uid(); $function$
;

DROP FUNCTION IF EXISTS public."get_db_intelligence" CASCADE;
CREATE OR REPLACE FUNCTION public.get_db_intelligence()
 RETURNS TABLE(obj_type text, obj_name text, obj_def text)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
            BEGIN
                -- Fetch Functions
                RETURN QUERY 
                SELECT 'FUNCTION'::text, proname::text, pg_get_functiondef(oid)::text 
                FROM pg_proc WHERE pronamespace = 'public'::regnamespace AND proname NOT IN ('exec_sql', 'get_db_intelligence');
                
                -- Fetch Triggers
                RETURN QUERY
                SELECT 'TRIGGER'::text, tgname::text, pg_get_triggerdef(oid)::text 
                FROM pg_trigger WHERE tgisinternal = false;
            END; $function$
;

