   FROM profiles
  WHERE (profiles.id = auth.uid()))));
CREATE POLICY "Admins manage invoices" ON public."invoices" FOR ALL TO public USING ((EXISTS ( SELECT 1
   FROM profiles
  WHERE ((profiles.id = auth.uid()) AND (profiles.is_admin = true)))));
